"""Post-process the auto-generated K8s CRD API reference for Fern.

Reads docs/kubernetes/api-reference.md (generated by crd-ref-docs)
and reformats it with Fern components:

  - Tabs for v1alpha1 / v1beta1 API groups
  - <details>/<summary> around each type definition
  - CardGroup at the top for the main resource types

This script does NOT modify the content -- only wraps it in Fern MDX
components for better navigation.  It is safe to re-run after each
``make generate-api-docs`` in deploy/operator/.

Usage (from repository root):
    python3 docs/scripts/fernify_k8s_api.py
"""

from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent))
from _fern_helpers import REPO_ROOT, escape_jsx_attr, render_details  # noqa: E402

DEFAULT_INPUT = REPO_ROOT / "docs" / "kubernetes" / "api-reference.md"

RESOURCE_META: dict[str, dict[str, str]] = {
    "DynamoCheckpoint": {
        "icon": "regular database",
        "desc": "Model checkpoint management and storage for inference workers.",
        "src": "api/v1alpha1/dynamocheckpoint_types.go",
    },
    "DynamoComponentDeployment": {
        "icon": "regular cube",
        "desc": "Individual component (Frontend, worker, Planner) within a graph.",
        "src": "api/v1alpha1/dynamocomponentdeployment_types.go",
    },
    "DynamoGraphDeployment": {
        "icon": "regular diagram-project",
        "desc": "Full inference graph with component topology and scaling.",
        "src": "api/v1alpha1/dynamographdeployment_types.go",
    },
    "DynamoGraphDeploymentRequest": {
        "icon": "regular file-lines",
        "desc": "SLA-driven deployment request with automated profiling.",
        "src": "api/v1alpha1/dynamographdeploymentrequest_types.go",
    },
    "DynamoGraphDeploymentScalingAdapter": {
        "icon": "regular arrows-up-down",
        "desc": "Scaling adapter for HPA, KEDA, or Planner autoscaling.",
        "src": "api/v1alpha1/dynamographdeploymentscalingadapter_types.go",
    },
    "DynamoModel": {
        "icon": "regular brain",
        "desc": "Model metadata and serving configuration.",
        "src": "api/v1alpha1/dynamo_model_types.go",
    },
}

OPERATOR_SRC = "https://github.com/ai-dynamo/dynamo/tree/main/deploy/operator"
OPERATOR_DIR = REPO_ROOT / "deploy" / "operator"

_TYPE_HEADING_RE = re.compile(r"^####\s+(\S+)\s*$")
_RESOURCE_LINK_RE = re.compile(r"^-\s+\[(\w+)\]")
_DEFAULT_DESC = "Custom resource for the Dynamo operator."


# ---------------------------------------------------------------------------
# Source discovery and extraction
# ---------------------------------------------------------------------------


def _discover_go_source(resource_name: str) -> str:
    """Find the Go source file for a resource type by naming convention."""
    if not OPERATOR_DIR.exists():
        return ""

    name_lower = resource_name.lower()
    base = name_lower.removeprefix("dynamo")

    patterns = [
        f"{name_lower}_types.go",
        f"dynamo_{base}_types.go",
        f"{base}_types.go",
    ]

    for api_dir in sorted(OPERATOR_DIR.glob("api/*")):
        if not api_dir.is_dir():
            continue
        for pattern in patterns:
            candidate = api_dir / pattern
            if candidate.exists():
                return str(candidate.relative_to(OPERATOR_DIR))
    return ""


def _extract_resource_description(
    lines: list[str],
    resource_name: str,
    start: int,
    end: int,
) -> str:
    """Extract the first-line description for a resource type.

    Returns empty string if not found.
    """
    heading_re = re.compile(rf"^####\s+{re.escape(resource_name)}\s*$")
    in_resource = False
    for i in range(start, end):
        line = lines[i]
        if heading_re.match(line):
            in_resource = True
            continue
        if not in_resource:
            continue
        stripped = line.strip()
        if stripped and not stripped.startswith("_") and not stripped.startswith("|"):
            return stripped[:77] + "..." if len(stripped) > 80 else stripped
        if stripped.startswith("#"):
            break
    return ""


# ---------------------------------------------------------------------------
# Section parsing
# ---------------------------------------------------------------------------


def _parse_sections(lines: list[str]) -> dict[str, tuple[int, int]]:
    """Find the line ranges of the major document sections."""
    markers: dict[str, int] = {}
    for i, line in enumerate(lines):
        stripped = line.rstrip()
        if stripped == "## nvidia.com/v1alpha1":
            markers["v1alpha1_start"] = i
        elif stripped == "## nvidia.com/v1beta1":
            markers["v1beta1_start"] = i
        elif stripped == "# Operator Default Values Injection":
            markers["footer_start"] = i

    return {
        "front_matter": (0, markers.get("v1alpha1_start", 0)),
        "v1alpha1": (
            markers.get("v1alpha1_start", 0),
            markers.get("v1beta1_start", markers.get("footer_start", len(lines))),
        ),
        "v1beta1": (
            markers.get("v1beta1_start", len(lines)),
            markers.get("footer_start", len(lines)),
        ),
        "footer": (markers.get("footer_start", len(lines)), len(lines)),
    }


def _find_type_headings(
    lines: list[str], start: int, end: int
) -> list[tuple[int, str]]:
    """Find all #### TypeName headings in a line range."""
    headings: list[tuple[int, str]] = []
    for i in range(start, end):
        m = _TYPE_HEADING_RE.match(lines[i])
        if m:
            headings.append((i, m.group(1)))
    return headings


def _find_resource_types(lines: list[str], start: int, end: int) -> list[str]:
    """Extract the resource type names from a ### Resource Types list."""
    resources: list[str] = []
    in_list = False
    for i in range(start, end):
        stripped = lines[i].strip()
        if stripped == "### Resource Types":
            in_list = True
            continue
        if not in_list:
            continue
        m = _RESOURCE_LINK_RE.match(stripped)
        if m:
            resources.append(m.group(1))
        elif stripped and not stripped.startswith("-"):
            break
    return resources


# ---------------------------------------------------------------------------
# Wrapping content in Fern components
# ---------------------------------------------------------------------------


def _wrap_types_in_details(
    lines: list[str],
    start: int,
    end: int,
) -> list[str]:
    """Wrap each #### type in a <details>/<summary> block."""
    headings = _find_type_headings(lines, start, end)
    if not headings:
        return lines[start:end]

    result: list[str] = []
    result.extend(lines[start : headings[0][0]])

    for idx, (line_num, type_name) in enumerate(headings):
        next_line = headings[idx + 1][0] if idx + 1 < len(headings) else end
        body_lines = lines[line_num + 1 : next_line]

        desc = _first_content_line(body_lines)
        title = escape_jsx_attr(f"{type_name} — {desc}") if desc else type_name

        body = "".join(body_lines)
        result.append(render_details(title, body))
        result.append("\n")

    return result


def _first_content_line(body_lines: list[str]) -> str:
    """Extract the first non-empty, non-metadata line from body lines."""
    for bl in body_lines:
        stripped = bl.strip()
        if stripped and not stripped.startswith("_") and not stripped.startswith("|"):
            return stripped
    return ""


def _build_resource_card_group(
    v1alpha1_resources: list[str],
    v1beta1_resources: list[str],
    md_lines: list[str],
    v1a_range: tuple[int, int],
    v1b_range: tuple[int, int],
) -> list[str]:
    """Build a CardGroup linking to Go source for each resource type."""
    all_resources = list(dict.fromkeys(v1alpha1_resources + v1beta1_resources))
    if not all_resources:
        return []

    output: list[str] = []
    cols = min(len(all_resources), 3)
    output.append(f"<CardGroup cols={{{cols}}}>\n\n")

    for name in all_resources:
        meta = _resolve_resource_meta(name, md_lines, v1a_range, v1b_range)
        href = f' href="{OPERATOR_SRC}/{meta["src"]}"' if meta["src"] else ""
        output.append(
            f'  <Card title="{name}" icon="{meta["icon"]}"{href}>\n'
            f'    {meta["desc"]}\n'
            f"  </Card>\n\n"
        )
    output.append("</CardGroup>\n\n")
    return output


def _resolve_resource_meta(
    name: str,
    md_lines: list[str],
    v1a_range: tuple[int, int],
    v1b_range: tuple[int, int],
) -> dict[str, str]:
    """Resolve icon, description, and source path for a resource."""
    if name in RESOURCE_META:
        meta = RESOURCE_META[name]
        return {
            "icon": meta.get("icon", "regular cube"),
            "desc": meta.get("desc", "Custom resource for the Dynamo operator."),
            "src": meta.get("src", ""),
        }
    desc = _extract_resource_description(md_lines, name, *v1a_range)
    if not desc:
        desc = _extract_resource_description(md_lines, name, *v1b_range)
    if not desc:
        desc = _DEFAULT_DESC
    return {"icon": "regular cube", "desc": desc, "src": _discover_go_source(name)}


# ---------------------------------------------------------------------------
# Document assembly
# ---------------------------------------------------------------------------


def _build_tabbed_content(
    lines: list[str],
    v1a_range: tuple[int, int],
    v1b_range: tuple[int, int],
    v1alpha1_resources: list[str],
    v1beta1_resources: list[str],
) -> list[str]:
    """Build the Tabs block containing v1alpha1 and v1beta1 content."""
    result: list[str] = ["<Tabs>\n\n"]

    result.append('<Tab title="v1alpha1">\n\n')
    result.extend(_wrap_types_in_details(lines, *v1a_range))
    result.append("\n</Tab>\n\n")

    result.append('<Tab title="v1beta1">\n\n')
    result.extend(_wrap_types_in_details(lines, *v1b_range))
    result.append("\n</Tab>\n\n")

    result.append("</Tabs>\n\n")
    return result


def _assemble_document(
    lines: list[str],
    sections: dict[str, tuple[int, int]],
    card_group: list[str],
    tabbed_content: list[str],
) -> str:
    """Assemble the final document from parts."""
    result: list[str] = []
    fm_start, fm_end = sections["front_matter"]
    ft_start, ft_end = sections["footer"]

    result.extend(lines[fm_start:fm_end])
    result.extend(card_group)
    result.extend(tabbed_content)
    result.extend(lines[ft_start:ft_end])

    return "".join(result)


def fernify(input_path: Path) -> str:
    """Reformat the K8s API reference with Fern components."""
    lines = input_path.read_text().splitlines(keepends=True)
    # Ensure last line has a newline
    if lines and not lines[-1].endswith("\n"):
        lines[-1] += "\n"

    sections = _parse_sections(lines)
    v1a_range = sections["v1alpha1"]
    v1b_range = sections["v1beta1"]

    v1alpha1_resources = _find_resource_types(lines, *v1a_range)
    v1beta1_resources = _find_resource_types(lines, *v1b_range)

    print(
        f"  v1alpha1: {len(v1alpha1_resources)} resources, types {v1a_range[0]}-{v1a_range[1]}"
    )
    print(
        f"  v1beta1: {len(v1beta1_resources)} resources, types {v1b_range[0]}-{v1b_range[1]}"
    )

    card_group = _build_resource_card_group(
        v1alpha1_resources,
        v1beta1_resources,
        lines,
        v1a_range,
        v1b_range,
    )

    tabbed_content = _build_tabbed_content(
        lines,
        v1a_range,
        v1b_range,
        v1alpha1_resources,
        v1beta1_resources,
    )

    return _assemble_document(lines, sections, card_group, tabbed_content)


# ---------------------------------------------------------------------------
# Main
# ---------------------------------------------------------------------------


def main() -> None:
    """Entry point: parse args and fernify the K8s API reference."""
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "input",
        nargs="?",
        type=Path,
        default=DEFAULT_INPUT,
        help="Path to api-reference.md (default: docs/kubernetes/api-reference.md)",
    )
    parser.add_argument(
        "--output",
        type=Path,
        default=None,
        help="Output path (default: overwrite input file)",
    )
    args = parser.parse_args()

    if not args.input.exists():
        sys.exit(f"Input file not found: {args.input}")

    print(f"Fernifying {args.input}...")
    content = fernify(args.input)

    out_path = args.output or args.input
    out_path.write_text(content)
    line_count = content.count("\n")
    print(f"  -> {out_path} ({line_count} lines)")


if __name__ == "__main__":
    main()
